import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);

  const [darkMode, setDarkMode] = useState(false);
  const [adminMode, setAdminMode] = useState(false);
  const [adminNote, setAdminNote] = useState("");

  const claimId = `CLM-${Date.now()}`;

  /* ---------------- Fraud Score Animation ---------------- */
  useEffect(() => {
    if (!result) return;

    let start = 0;
    const end = result.fraud_confidence_score || 0;
    const duration = 1200;
    const stepTime = 20;
    const step = end / (duration / stepTime);

    const interval = setInterval(() => {
      start += step;
      if (start >= end) {
        start = end;
        clearInterval(interval);
      }
      setAnimatedScore(Math.round(start));
    }, stepTime);

    return () => clearInterval(interval);
  }, [result]);

  /* ---------------- Helpers ---------------- */

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => {
    if (score <= 50) return "#16a34a";
    if (score <= 80) return "#f59e0b";
    return "#dc2626";
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#dc2626";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#16a34a";
  };

  /* ---------------- File Handling ---------------- */

  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    if (!selected) return;

    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) throw new Error("Server error");

      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
    setAdminNote("");
  };

  /* ---------------- Professional HTML Report ---------------- */

  const downloadReport = () => {
    if (!result) return;

    const html = `
      <html>
      <head>
        <title>ClaimPilot AI Report</title>
        <style>
          body { font-family: Arial; padding: 40px; }
          h1 { color: #1e40af; }
          .box { margin-top: 20px; }
          .highlight { font-weight: bold; }
        </style>
      </head>
      <body>
        <h1>ClaimPilot AI - Audit Report</h1>
        <p><strong>Claim ID:</strong> ${claimId}</p>
        <p><strong>Date:</strong> ${new Date().toLocaleString()}</p>

        <div class="box">
          <h3>Total Estimate</h3>
          <p class="highlight">PKR ${result.total_estimate_pkr}</p>
        </div>

        <div class="box">
          <h3>Fraud Score</h3>
          <p class="highlight">${result.fraud_confidence_score}% - ${riskLevel(
      result.fraud_confidence_score
    )}</p>
        </div>

        <div class="box">
          <h3>Verdict</h3>
          <p>${result.verdict}</p>
        </div>

        <div class="box">
          <h3>Damaged Parts</h3>
          <ul>
            ${(result.damaged_parts || [])
              .map((p) => `<li>${p}</li>`)
              .join("")}
          </ul>
        </div>

        <div class="box">
          <h3>Admin Notes</h3>
          <p>${adminNote || "N/A"}</p>
        </div>
      </body>
      </html>
    `;

    const blob = new Blob([html], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ClaimPilot_Report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const theme = darkMode ? dark : light;

  /* ---------------- UI ---------------- */

  return (
    <div style={theme.page}>
      <div style={theme.container}>
        <header style={theme.header}>
          <h1 style={theme.logo}>ClaimPilot AI</h1>
          <p style={theme.tagline}>
            Intelligent Vehicle Damage Assessment & Fraud Detection
          </p>

          <div style={theme.toggleRow}>
            <button style={theme.toggleBtn} onClick={() => setDarkMode(!darkMode)}>
              {darkMode ? "Light Mode" : "Dark Mode"}
            </button>
            <button
              style={theme.toggleBtn}
              onClick={() => setAdminMode(!adminMode)}
            >
              {adminMode ? "User Mode" : "Admin Mode"}
            </button>
          </div>
        </header>

        {/* Upload Card */}
        <div
          style={theme.uploadCard}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            handleFileChange({ target: { files: [e.dataTransfer.files[0]] } });
          }}
        >
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? theme.previewZoom : theme.preview}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <label style={theme.uploadLabel}>
            {file ? file.name : "Click or Drag Image Here"}
            <input
              type="file"
              accept="image/*"
              hidden
              onChange={handleFileChange}
            />
          </label>

          <div style={theme.buttonRow}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={theme.primaryBtn}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>

            {file && (
              <button onClick={handleReset} style={theme.resetBtn}>
                Reset
              </button>
            )}
          </div>

          {error && <p style={theme.error}>{error}</p>}
        </div>

        {/* Result */}
        {result && (
          <div style={theme.resultCard}>
            <h2>Audit Summary</h2>

            <div style={theme.stats}>
              <div style={theme.statBox}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>

              <div style={theme.statBox}>
                <p>Fraud Score</p>
                <svg viewBox="0 0 36 36" style={theme.gauge}>
                  <path
                    stroke="#eee"
                    fill="none"
                    strokeWidth="2.8"
                    d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                  />
                  <path
                    stroke={gaugeColor(animatedScore)}
                    strokeDasharray={`${animatedScore}, 100`}
                    fill="none"
                    strokeWidth="2.8"
                    d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                    style={{ transition: "stroke-dasharray 1s ease" }}
                  />
                  <text x="18" y="20.5" style={theme.gaugeText}>
                    {animatedScore}%
                  </text>
                </svg>
                <p style={{ color: gaugeColor(animatedScore), fontWeight: 600 }}>
                  {riskLevel(animatedScore)}
                </p>
              </div>

              <div
                style={{
                  ...theme.statBox,
                  color: verdictColor(result.verdict),
                }}
              >
                <p>Verdict</p>
                <h3>{result.verdict}</h3>
              </div>
            </div>

            {adminMode && (
              <div style={{ marginTop: 20 }}>
                <h3>Admin Notes</h3>
                <textarea
                  value={adminNote}
                  onChange={(e) => setAdminNote(e.target.value)}
                  style={theme.textarea}
                  placeholder="Write internal notes..."
                />
              </div>
            )}

            <button onClick={downloadReport} style={theme.downloadBtn}>
              Download Professional Report
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

